package agent

import (
	"encoding/json"
	"os"
	"path/filepath"
	"time"
)

const (
	routingOutcomeFileName = "routing-outcomes.jsonl"
	burnSummaryFileName    = "burn-summaries.jsonl"
)

// RoutingMetricsStore persists minimal routing outcome and quota snapshot data.
type RoutingMetricsStore struct {
	Dir string
}

// NewRoutingMetricsStore creates a store rooted at dir.
func NewRoutingMetricsStore(dir string) *RoutingMetricsStore {
	return &RoutingMetricsStore{Dir: dir}
}

func (s *RoutingMetricsStore) outcomeFile() string {
	return filepath.Join(s.Dir, routingOutcomeFileName)
}

func (s *RoutingMetricsStore) burnFile() string {
	return filepath.Join(s.Dir, burnSummaryFileName)
}

// AppendOutcome writes one routing outcome record.
func (s *RoutingMetricsStore) AppendOutcome(outcome RoutingOutcome) error {
	return appendJSONLRecord(s.outcomeFile(), outcome)
}

// ReadOutcomes loads all recorded routing outcomes.
func (s *RoutingMetricsStore) ReadOutcomes() ([]RoutingOutcome, error) {
	return ReadAllJSONL[RoutingOutcome](s.outcomeFile())
}

// ReadBurnSummaries loads stored burn summaries.
func (s *RoutingMetricsStore) ReadBurnSummaries() ([]BurnSummary, error) {
	return ReadAllJSONL[BurnSummary](s.burnFile())
}

func appendJSONLRecord(path string, v any) error {
	if err := os.MkdirAll(filepath.Dir(path), 0o755); err != nil {
		return err
	}
	data, err := json.Marshal(v)
	if err != nil {
		return err
	}
	f, err := os.OpenFile(path, os.O_CREATE|os.O_WRONLY|os.O_APPEND, 0o644)
	if err != nil {
		return err
	}
	defer f.Close()
	if _, err := f.Write(append(data, '\n')); err != nil {
		return err
	}
	return nil
}

func (r *Runner) recordRoutingOutcome(result *Result, elapsed time.Duration, opts RunArgs) {
	if r == nil || result == nil || r.Config.SessionLogDir == "" {
		return
	}

	harness, _ := r.registry.Get(result.Harness)
	canonicalTarget := result.Model
	if canonicalTarget == "" {
		canonicalTarget = opts.Model
	}
	if canonicalTarget == "" && harness.DefaultModel != "" {
		canonicalTarget = harness.DefaultModel
	}
	if canonicalTarget == "" {
		canonicalTarget = result.Harness
	}

	outcome := RoutingOutcome{
		Harness:         result.Harness,
		Surface:         harness.Surface,
		CanonicalTarget: canonicalTarget,
		Model:           result.Model,
		ObservedAt:      time.Now().UTC(),
		Success:         result.ExitCode == 0 && result.Error == "",
		LatencyMS:       int(elapsed.Milliseconds()),
		InputTokens:     result.InputTokens,
		OutputTokens:    result.OutputTokens,
		CostUSD:         result.CostUSD,
		NativeSessionID: result.AgentSessionID,
	}

	if opts.Correlation != nil {
		outcome.TraceID = opts.Correlation["trace_id"]
		outcome.SpanID = opts.Correlation["span_id"]
		if outcome.NativeSessionID == "" {
			outcome.NativeSessionID = opts.Correlation["native_session_id"]
		}
		if outcome.NativeLogRef == "" {
			outcome.NativeLogRef = opts.Correlation["native_log_ref"]
		}
	}

	_ = NewRoutingMetricsStore(r.Config.SessionLogDir).AppendOutcome(outcome)
}

// enrichUsageRowsWithRoutingSignals annotates usage rows with per-harness
// routing signals from the upstream agent service. When the service is
// unavailable the rows are returned unchanged.
func enrichUsageRowsWithRoutingSignals(workDir string, rows []usageRow) []usageRow {
	svc, err := agent.NewServiceFromWorkDir(workDir)
	if err != nil || svc == nil {
		return rows
	}
	ctx := context.Background()
	infos, err := svc.ListHarnesses(ctx)
	if err != nil {
		return rows
	}
	byName := make(map[string]agentlib.HarnessInfo, len(infos))
	for _, info := range infos {
		byName[info.Name] = info
	}
	now := time.Now()
	for i := range rows {
		info, ok := byName[rows[i].Harness]
		if !ok {
			continue
		}
		signal := harnessInfoToRoutingSignal(info, now)
		applyUsageCostBasis(&rows[i], info.IsSubscription)
		rows[i].QuotaState = signal.CurrentQuota.State
		if signal.Provider == "" && signal.Source.Kind == "" {
			continue
		}
		rows[i].SignalProvider = signal.Provider
		rows[i].SignalKind = signal.Source.Kind
		rows[i].SignalFreshness = signal.Source.Freshness
		rows[i].SignalBasis = signal.Source.Basis
		rows[i].NativeInputTokens = signal.HistoricalUsage.InputTokens
		rows[i].NativeOutputTokens = signal.HistoricalUsage.OutputTokens
		rows[i].NativeTotalTokens = signal.HistoricalUsage.TotalTokens
		rows[i].NativeSessionCount = signal.HistoricalUsage.SessionCount
		rows[i].NativeQuotaUsedPercent = signal.CurrentQuota.UsedPercent
	}
	return rows
}

func readUsageSessionIndexRecords(logDir, harnessFilter string, since time.Time) ([]usageSessionRecord, error) {
	entries, err := agent.ReadSessionIndex(logDir, agent.SessionIndexQuery{StartedAfter: &since})
	if err != nil {
		return nil, err
	}
	records := make([]usageSessionRecord, 0, len(entries))
	for _, idx := range entries {
		entry := agent.SessionIndexEntryToLegacy(idx)
		if harnessFilter != "" && entry.Harness != harnessFilter {
			continue
		}
		records = append(records, usageSessionRecord{
			entry: entry,
		})
	}
	sort.Slice(records, func(i, j int) bool {
		return records[i].entry.Timestamp.Before(records[j].entry.Timestamp)
	})
	return records, nil
}

// formatComma formats an integer with comma separators.
func formatComma(n int) string {
	s := strconv.Itoa(n)
	if len(s) <= 3 {
		return s
	}
	var b strings.Builder
	start := len(s) % 3
	b.WriteString(s[:start])
	for i := start; i < len(s); i += 3 {
		if i > 0 {
			b.WriteByte(',')
		}
		b.WriteString(s[i : i+3])
	}
	return b.String()
}

func renderUsageTable(cmd *cobra.Command, rows []usageRow) error {
	out := cmd.OutOrStdout()
	fmt.Fprintf(out, "%-12s  %8s  %13s  %14s  %10s  %-15s  %12s  %-8s  %-18s  %-10s\n",
		"HARNESS", "SESSIONS", "INPUT TOKENS", "OUTPUT TOKENS", "EST. COST", "COST BASIS", "AVG DURATION", "QUOTA", "SOURCE", "FRESHNESS")

	var totalSessions int
	var totalInput, totalOutput int
	var totalCost float64
	var totalDurMS float64

	for _, r := range rows {
		source := r.SignalProvider
		if r.SignalKind != "" {
			if source != "" {
				source += "/"
			}
			source += r.SignalKind
		}
		fmt.Fprintf(out, "%-12s  %8d  %13s  %14s  %10s  %-15s  %11.1fs  %-8s  %-18s  %-10s\n",
			r.Harness,
			r.Sessions,
			formatComma(r.InputTokens),
			formatComma(r.OutputTokens),
			fmt.Sprintf("$%.2f", r.CostUSD),
			r.CostBasis,
			r.AvgDurationMS/1000.0,
			r.QuotaState,
			source,
			r.SignalFreshness,
		)
		totalSessions += r.Sessions
		totalInput += r.InputTokens
		totalOutput += r.OutputTokens
		totalCost += r.CostUSD
		totalDurMS += r.AvgDurationMS * float64(r.Sessions)
	}

	var avgTotal float64
	if totalSessions > 0 {
		avgTotal = totalDurMS / float64(totalSessions)
	}
	fmt.Fprintf(out, "%-12s  %8d  %13s  %14s  %10s  %-15s  %11.1fs\n",
		"TOTAL",
		totalSessions,
		formatComma(totalInput),
		formatComma(totalOutput),
		fmt.Sprintf("$%.2f", totalCost),
		"",
		avgTotal/1000.0,
	)
	return nil
}

