// filterProviderOutcomes returns outcomes for a given harness within the last windowDays days.
func filterProviderOutcomes(outcomes []agent.RoutingOutcome, harnessName string, now time.Time, windowDays int) []agent.RoutingOutcome {
	cutoff := now.Add(-time.Duration(windowDays) * 24 * time.Hour)
	result := make([]agent.RoutingOutcome, 0)
	for _, o := range outcomes {
		if o.Harness == harnessName && o.ObservedAt.After(cutoff) {
			result = append(result, o)
		}
	}
	return result
}

// computeProviderPerformance computes latency percentiles and success rate from outcomes.
// Returns -1 sentinels when sample_count < 3 per FEAT-014.
func computeProviderPerformance(outcomes []agent.RoutingOutcome) ProviderPerformance {
	perf := ProviderPerformance{
		P50LatencyMS: -1,
		P95LatencyMS: -1,
		SuccessRate:  -1,
		SampleCount:  len(outcomes),
		Window:       "7d",
	}
	if len(outcomes) < 3 {
		return perf
	}
	var successCount int
	latencies := make([]int, 0, len(outcomes))
	for _, o := range outcomes {
		if o.Success {
			successCount++
		}
		latencies = append(latencies, o.LatencyMS)
	}
	perf.SuccessRate = float64(successCount) / float64(len(outcomes))
	sort.Ints(latencies)
	perf.P50LatencyMS = latencies[len(latencies)/2]
	p95Idx := int(float64(len(latencies)-1) * 0.95)
	perf.P95LatencyMS = latencies[p95Idx]
	return perf
}

// providerPerformanceFromRouteStatus derives recent provider performance from
// the live Fizeau route-status report, which replaces the old DDx metrics-store
// read model for current routing semantics.
func providerPerformanceFromRouteStatus(report *agentlib.RouteStatusReport, providerName string) ProviderPerformance {
	perf := ProviderPerformance{
		P50LatencyMS: -1,
		P95LatencyMS: -1,
		SuccessRate:  -1,
		SampleCount:  0,
		Window:       "7d",
	}
	if report == nil {
		return perf
	}
	var latencies []int
	var reliabilityTotal float64
	for _, route := range report.Routes {
		for _, candidate := range route.Candidates {
			if candidate.Provider != providerName {
				continue
			}
			perf.SampleCount++
			reliabilityTotal += candidate.ProviderReliabilityRate
			if candidate.RecentLatencyMS > 0 {
				latencies = append(latencies, int(candidate.RecentLatencyMS+0.5))
			}
		}
	}
	if perf.SampleCount < 3 {
		return perf
	}
	perf.SuccessRate = reliabilityTotal / float64(perf.SampleCount)
	if len(latencies) == 0 {
		return perf
	}
	sort.Ints(latencies)
	perf.P50LatencyMS = latencies[len(latencies)/2]
	p95Idx := int(float64(len(latencies)-1) * 0.95)
	perf.P95LatencyMS = latencies[p95Idx]
	return perf
}

// collectHarnessSignalSources builds the signal_sources array from the direct
// HarnessInfo fields.
func collectHarnessSignalSources(info agentlib.HarnessInfo) []string {
	seen := make(map[string]struct{})
	add := func(value string) {
		if value = normalizeHarnessSignalSource(value); value != "" {
			seen[value] = struct{}{}
		}
	}
	if info.Account != nil {
		add(info.Account.Source)
	}
	if info.Quota != nil {
		add(info.Quota.Source)
	}
	for _, window := range info.UsageWindows {
		add(window.Source)
	}
	if len(seen) == 0 {
		return []string{"none"}
	}
	sources := make([]string, 0, len(seen))
	for source := range seen {
		sources = append(sources, source)
	}
	sort.Strings(sources)
	return sources
}

var staleHarnessSignalSources = map[string]struct{}{
	"stats-cache":        {},
	"quota-snapshot":     {},
	"http-balance":       {},
	"http-models":        {},
	"recent-session-log": {},
	"ddx-metrics":        {},
	"routing-outcomes":   {},
	"burn-summaries":     {},
}

func normalizeHarnessSignalSource(value string) string {
	value = strings.TrimSpace(value)
	if value == "" {
		return ""
	}
	lower := strings.ToLower(value)
	if _, stale := staleHarnessSignalSources[lower]; stale {
		return ""
	}
	for stale := range staleHarnessSignalSources {
		if strings.Contains(lower, stale) {
			return ""
		}
	}
	return value
}

// providerFreshnessTS returns the latest direct capture timestamp available on
// the HarnessInfo.
func providerFreshnessTS(info agentlib.HarnessInfo) time.Time {
	var latest time.Time
	update := func(ts time.Time) {
		if ts.IsZero() {
			return
		}
		ts = ts.UTC()
		if ts.After(latest) {
			latest = ts
		}
	}
	if info.Account != nil {
		update(info.Account.CapturedAt)
	}
	if info.Quota != nil {
		update(info.Quota.CapturedAt)
	}
	for _, window := range info.UsageWindows {
		update(window.CapturedAt)
	}
	return latest
}

